arguments.argument:
if type=0 or type=4
{
  baseColor=c_fuchsia
  resType[1]=4
}
else if type=1 or type=5
{
  baseColor=c_orange
  resType[5]=4
}
else if type=2 or type=6
{
  baseColor=c_blue
  resType[3]=4
}
else if type=3 or type=7
{
  baseColor=c_green
  resType[2]=4
}
image_blend=baseColor
